class FrontMiddleBackQueue {
    constructor() {
        this.left = [];
        this.right = [];
    }

    _rebalance() {
        if (this.left.length > this.right.length + 1) {
            this.right.unshift(this.left.pop());
        } else if (this.right.length > this.left.length) {
            this.left.push(this.right.shift());
        }
    }

    pushFront(val) {
        this.left.unshift(val);
        this._rebalance();
    }

    pushMiddle(val) {
        if (this.left.length > this.right.length) {
            this.right.unshift(this.left.pop());
        }
        this.left.push(val);
        this._rebalance();
    }

    pushBack(val) {
        this.right.push(val);
        this._rebalance();
    }

    popFront() {
        if (this.left.length === 0 && this.right.length === 0) return -1;
        const val = this.left.length ? this.left.shift() : this.right.shift();
        this._rebalance();
        return val;
    }

    popMiddle() {
        if (this.left.length === 0 && this.right.length === 0) return -1;
        const val = this.left.pop();
        this._rebalance();
        return val;
    }

    popBack() {
        if (this.left.length === 0 && this.right.length === 0) return -1;
        const val = this.right.length ? this.right.pop() : this.left.pop();
        this._rebalance();
        return val;
    }
}
